sql:
SELECT c.category_name, COUNT(d.dataset_id) AS num_of_datasets
FROM datasets d
JOIN categories c ON d.category_id = c.category_id
WHERE d.year_id BETWEEN (
    SELECT year_id FROM years WHERE year_name = '2010'
) AND (
    SELECT year_id FROM years WHERE year_name = '2020'
)
GROUP BY c.category_name;

SELECT AVG(data_size) AS average_data_size
FROM datasets
WHERE category_id IN (1, 2, 3);

SELECT MIN(data_size) as min_size, MAX(data_size) as max_size 
FROM datasets 
WHERE site_id = 1 OR year_id = 0;
